import { useRef, useState } from 'react';

export function MouseImageTrail() {
  const containerRef = useRef(null);
  const [items, setItems] = useState([]);
  const lastMousePos = useRef({ x: 0, y: 0 });
  const itemCounter = useRef(0);

  const handleMouseMove = (e) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const dist = Math.hypot(x - lastMousePos.current.x, y - lastMousePos.current.y);

    // Spawn a new trail card every 60px of movement
    if (dist > 60) {
      lastMousePos.current = { x, y };
      const id = itemCounter.current++;

      // Generate a random gradient color for the trail item card
      const gradients = [
        'from-pink-500 to-rose-500',
        'from-purple-500 to-indigo-500',
        'from-cyan-500 to-blue-500',
        'from-emerald-500 to-teal-500',
        'from-amber-500 to-orange-500'
      ];
      const randomGrad = gradients[id % gradients.length];

      const newItem = {
        id,
        x,
        y,
        gradient: randomGrad,
        rotation: (Math.random() - 0.5) * 30
      };

      setItems((prev) => [...prev, newItem]);

      // Auto-cleanup after 800ms
      setTimeout(() => {
        setItems((prev) => prev.filter((item) => item.id !== id));
      }, 800);
    }
  };

  return (
    <div
      ref={containerRef}
      onMouseMove={handleMouseMove}
      className="relative h-[400px] w-full overflow-hidden rounded-2xl border border-border bg-neutral-950 flex items-center justify-center select-none cursor-crosshair"
    >
      <div className="text-center z-10 pointer-events-none">
        <p className="text-xl font-bold tracking-tight text-white/90">
          Move mouse across this panel
        </p>
        <p className="text-xs text-neutral-500 mt-1">
          Generates a staggered gradient card trail
        </p>
      </div>

      {/* Trail Cards Render */}
      {items.map((item) => (
        <div
          key={item.id}
          style={{
            left: item.x,
            top: item.y,
            transform: `translate(-50%, -50%) rotate(${item.rotation}deg)`,
            pointerEvents: 'none'
          }}
          className={`absolute h-20 w-16 rounded-xl border border-white/20 bg-gradient-to-br ${item.gradient} opacity-80 shadow-2xl animate-[trail-fade_0.8s_ease-out_forwards]`}
        />
      ))}

      <style>{`
        @keyframes trail-fade {
          0% {
            opacity: 0.8;
            scale: 0.2;
          }
          20% {
            opacity: 0.9;
            scale: 1.05;
          }
          100% {
            opacity: 0;
            scale: 0.5;
            transform: translate(-50%, -50%) translateY(40px) scale(0.5);
          }
        }
      `}</style>
    </div>
  );
}

