import { useEffect, useRef } from 'react';

export function VectorWaveCanvas() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    let animationFrameId;

    const resizeCanvas = () => {
      canvas.width = canvas.parentElement.clientWidth;
      canvas.height = canvas.parentElement.clientHeight || 300;
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    let step = 0;
    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Draw three wave layers with varying attributes
      drawWave(ctx, canvas.width, canvas.height, step, 50, 'rgba(0, 173, 181, 0.15)', 0.005);
      drawWave(ctx, canvas.width, canvas.height, step + 100, 70, 'rgba(0, 173, 181, 0.08)', 0.003);
      drawWave(ctx, canvas.width, canvas.height, step + 200, 30, 'rgba(0, 173, 181, 0.2)', 0.007);

      step += 1;
      animationFrameId = requestAnimationFrame(render);
    };
    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', resizeCanvas);
    };
  }, []);

  const drawWave = (ctx, w, h, step, amplitude, fillStyle, frequency) => {
    ctx.beginPath();
    ctx.moveTo(0, h);

    for (let x = 0; x <= w; x += 10) {
      const y = h / 2 + Math.sin(x * frequency + step * 0.02) * amplitude;
      ctx.lineTo(x, y);
    }

    ctx.lineTo(w, h);
    ctx.lineTo(0, h);
    ctx.fillStyle = fillStyle;
    ctx.fill();
  };

  return (
    <div className="relative w-full h-[300px] border border-border bg-neutral-900 overflow-hidden rounded-2xl">
      <canvas ref={canvasRef} className="absolute inset-0 block w-full h-full" />
      <div className="absolute inset-0 flex items-center justify-center text-center p-6 z-10 pointer-events-none select-none">
        <div>
          <h4 className="text-lg font-bold tracking-tight text-white">Liquid Wave Simulator</h4>
          <p className="text-xs text-neutral-400 mt-0.5">Smooth vector waves rendering on canvas</p>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useRef } from 'react';

export function SparticlesCanvas() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    let animationFrameId;

    const resizeCanvas = () => {
      canvas.width = canvas.parentElement.clientWidth;
      canvas.height = canvas.parentElement.clientHeight || 300;
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    const particleCount = 60;
    const particles = [];

    for (let i = 0; i < particleCount; i++) {
      particles.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: Math.random() * 2 + 1,
        speedY: -(Math.random() * 0.5 + 0.2),
        speedX: (Math.random() - 0.5) * 0.3,
        opacity: Math.random() * 0.6 + 0.2
      });
    }

    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.forEach((p) => {
        p.y += p.speedY;
        p.x += p.speedX;

        // Reset particle if it floats past top boundary
        if (p.y < 0) {
          p.y = canvas.height;
          p.x = Math.random() * canvas.width;
        }
        if (p.x < 0 || p.x > canvas.width) {
          p.x = Math.random() * canvas.width;
        }

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(0, 173, 181, ${p.opacity})`;
        ctx.fill();
      });

      animationFrameId = requestAnimationFrame(render);
    };
    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', resizeCanvas);
    };
  }, []);

  return (
    <div className="relative w-full h-[300px] border border-border bg-neutral-950 overflow-hidden rounded-2xl">
      <canvas ref={canvasRef} className="absolute inset-0 block w-full h-full" />
      <div className="absolute inset-0 flex items-center justify-center text-center p-6 z-10 pointer-events-none select-none">
        <div>
          <h4 className="text-lg font-bold tracking-tight text-white">Sparticles Starfield</h4>
          <p className="text-xs text-neutral-400 mt-0.5">High-performance canvas particles background</p>
        </div>
      </div>
    </div>
  );
}
